#include <unistd.h>

#define SVGA_IO_PORT 0x3d0
#define SVGA_INDEX_PORT 0x3d0
#define SVGA_VALUE_PORT 0x3d1
#define SVGA_REG_ID 0
#define SVGA_REG_ENABLE 1
#define SVGA_REG_WIDTH 2
#define SVGA_REG_HEIGHT 3

// 写SVGA寄存器
void svga_write_reg(unsigned short reg, unsigned int value) {
    outl(reg, SVGA_INDEX_PORT);
    outl(value, SVGA_VALUE_PORT);
}

// 发送FIFO命令
void svga_send_fifo(unsigned int *cmd, int len) {
